import { Product, Review } from '../types';

const generateReviews = (count: number): Review[] => {
  const users = ['Alex R.', 'Sarah M.', 'Jordan K.', 'Taylor B.', 'Casey W.'];
  const comments = [
    'Amazing quality! Fits perfectly.',
    'Fast shipping and great packaging.',
    'Highly recommended, looks very premium.',
    'The best case I have ever owned.',
    'Excellent value for the price.'
  ];
  return Array.from({ length: count }, (_, i) => ({
    id: `rev-${i}`,
    user: users[i % users.length],
    rating: 4 + Math.random(),
    comment: comments[i % comments.length],
    date: '2 days ago'
  }));
};

const generateProducts = (): Product[] => {
  const categories = ['Clear Cases', 'MagSafe', 'Screen Protectors', 'Chargers', 'Lens Guards'];
  const baseProducts: Product[] = [];

  categories.forEach((cat) => {
    for (let i = 1; i <= 10; i++) {
      const id = `${cat.toLowerCase().replace(' ', '-')}-${i}`;
      baseProducts.push({
        id,
        name: `${cat} Premium ${i}`,
        category: cat,
        price: 19.99 + (i * 5),
        image: `https://picsum.photos/seed/${id}/600/600`,
        images: [
          `https://picsum.photos/seed/${id}-1/600/600`,
          `https://picsum.photos/seed/${id}-2/600/600`,
          `https://picsum.photos/seed/${id}-3/600/600`
        ],
        modelCompatibility: 'iPhone 15 Pro Max',
        description: `This high-performance ${cat} is engineered with premium materials to provide maximum protection and style for your device. Featuring a sleek design and precise cutouts.`,
        specifications: [
          'Material: High-Grade Polycarbonate',
          'Drop Protection: Up to 10ft',
          'Weight: 45g',
          'Warranty: 1 Year Limited'
        ],
        isBestSeller: i < 3,
        reviews: generateReviews(3)
      });
    }
  });

  return baseProducts;
};

export const products: Product[] = generateProducts();
