              value={formData.confirm}
              onChange={e => {setFormData({...formData, confirm: e.target.value}); if(errors.confirm) setErrors({...errors, confirm: undefined})}}
              disabled={isLoading}
            />
            {errors.confirm && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.confirm}</p>}
          </div>

          <button 
            type="submit" 
            disabled={isLoading}
            className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-blue-600 transition-all shadow-xl hover:shadow-blue-500/10 active:scale-[0.98] disabled:bg-gray-400 disabled:shadow-none flex items-center justify-center gap-2 mt-4"
          >
            {isLoading ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                Creating Account...
              </>
            ) : 'Create Account'}
          </button>
        </form>

        <div className="mt-8 pt-8 border-t text-center">
          <p className="text-sm text-gray-500">
