import React, { useState, useMemo } from 'react';
import { useApp } from '../../context/AppContext';

const AdminAnalytics: React.FC = () => {
  const { orders } = useApp();
  const [timeRange, setTimeRange] = useState<'7d' | '30d' | 'today'>('7d');

  // Simulated trend data based on timeRange
  const trendData = useMemo(() => {
    const dataPoints = timeRange === 'today' ? 12 : timeRange === '7d' ? 7 : 30;
    return Array.from({ length: dataPoints }, (_, i) => ({
      label: timeRange === 'today' ? `${i*2}h` : `Day ${i + 1}`,
      value: 1200 + Math.random() * 800 + (i * 50)
    }));
  }, [timeRange]);

  const maxVal = Math.max(...trendData.map(d => d.value));
  const minVal = Math.min(...trendData.map(d => d.value));
  const range = maxVal - minVal;

  const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
  const avgOrder = orders.length > 0 ? totalRevenue / orders.length : 0;

  // Simple SVG Path generator for the line chart
  const points = trendData.map((d, i) => {
    const x = (i / (trendData.length - 1)) * 100;
    const y = 100 - ((d.value - minVal) / range) * 80 - 10; // Normalized with some padding
    return `${x},${y}`;
  }).join(' ');

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <h3 className="text-2xl font-black text-slate-900 tracking-tight">Business Insights</h3>
        <div className="flex bg-white border border-slate-100 p-1 rounded-2xl shadow-sm">
          {(['today', '7d', '30d'] as const).map(range => (
            <button
              key={range}
              onClick={() => setTimeRange(range)}
              className={`px-6 py-2 rounded-xl text-xs font-bold uppercase tracking-widest transition-all ${
                timeRange === range ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-900'
              }`}
            >
              {range}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Total Revenue', value: `$${totalRevenue.toFixed(2)}`, trend: '+12.5%', color: 'text-green-500' },
          { label: 'Total Orders', value: orders.length, trend: '+5.2%', color: 'text-blue-500' },
          { label: 'Avg Order Value', value: `$${avgOrder.toFixed(2)}`, trend: '-1.8%', color: 'text-amber-500' },
          { label: 'Active Sessions', value: '142', trend: '+22%', color: 'text-purple-500' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
            <div className="flex items-end gap-3">
              <h4 className="text-3xl font-black text-slate-900 leading-none">{stat.value}</h4>
              <span className={`text-[10px] font-black mb-1 ${stat.color}`}>{stat.trend}</span>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm p-10">
        <div className="flex items-center justify-between mb-10">
          <div>
            <h4 className="font-black text-slate-900 text-xl">Revenue Growth</h4>
            <p className="text-sm text-slate-400">Aggregated sales performance for the selected period.</p>
          </div>
          <div className="flex gap-6">
            <div className="flex items-center gap-2">
              <span className="w-3 h-3 bg-blue-600 rounded-full"></span>
              <span className="text-xs font-bold text-slate-600">Revenue</span>
            </div>
          </div>
        </div>

        {/* Custom SVG Line Chart */}
        <div className="relative h-64 w-full">
          <svg className="w-full h-full overflow-visible" viewBox="0 0 100 100" preserveAspectRatio="none">
            {/* Grid lines */}
            {[0, 25, 50, 75, 100].map(y => (
              <line key={y} x1="0" y1={y} x2="100" y2={y} stroke="#f1f5f9" strokeWidth="0.5" />
            ))}
            {/* Main Line */}
            <polyline
              fill="none"
              stroke="#2563eb"
              strokeWidth="2"
              strokeLinejoin="round"
              strokeLinecap="round"
              points={points}
              className="transition-all duration-1000"
            />
            {/* Area under the line */}
            <path
              d={`M 0,100 L ${points} L 100,100 Z`}
              fill="url(#gradient)"
              className="opacity-10 transition-all duration-1000"
            />
            <defs>
              <linearGradient id="gradient" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="#2563eb" />
                <stop offset="100%" stopColor="white" />
              </linearGradient>
            </defs>
          </svg>

          {/* Legend labels */}
          <div className="flex justify-between mt-6 px-2">
             {trendData.filter((_, i) => i % (timeRange === '30d' ? 5 : 1) === 0).map((d, i) => (
               <span key={i} className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                 {d.label}
               </span>
             ))}
          </div>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-8">
        <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm p-8">
          <h4 className="font-black text-slate-900 text-lg mb-6">Payment Methods Ratio</h4>
          <div className="space-y-4">
            {[
              { label: 'bKash / Nagad', value: 65, color: 'bg-blue-600' },
