type CheckoutStep = 'shipping' | 'payment' | 'review' | 'success';

const CheckoutPage: React.FC = () => {
  const { cart, cartTotal, placeOrder } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<CheckoutStep>('shipping');
  const [lastOrder, setLastOrder] = useState<any>(null);

  // Form States
  const [shippingInfo, setShippingInfo] = useState<ShippingInfo>({
    fullName: '', phone: '', email: '', address: '', city: '', area: '', postalCode: '', note: ''
  });
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('COD');
  const [paymentDetails, setPaymentDetails] = useState({ phone: '', transactionId: '', cardName: '', cardNumber: '', expiry: '', cvv: '' });

  const shippingFee = cartTotal > 50 ? 0 : 9.99;
  const tax = cartTotal * 0.08;
  const total = cartTotal + shippingFee + tax;

  const handlePlaceOrder = () => {
    const order = placeOrder(shippingInfo, paymentMethod, paymentDetails);
    setLastOrder(order);
    setStep('success');
  };

  if (cart.length === 0 && step !== 'success') {
    return (
      <div className="max-w-xl mx-auto py-32 px-4 text-center">
        <h2 className="text-2xl font-bold mb-4">Your cart is empty.</h2>
        <Link to="/" className="text-blue-600 font-bold hover:underline">Return to Shop</Link>
      </div>
