import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../../../context/AppContext';

const LoginPage: React.FC = () => {
  const { login, socialLogin, rememberMe, setRememberMe } = useApp();
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState<{email?: string; password?: string; general?: string}>({});
  const [isLoading, setIsLoading] = useState(false);

  const validate = () => {
    const newErrors: typeof errors = {};
    if (!email) newErrors.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(email)) newErrors.email = 'Invalid email format';

    if (!password) newErrors.password = 'Password is required';
    else if (password.length < 6) newErrors.password = 'Password must be at least 6 characters';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);
    setTimeout(() => {
      if (email === 'error@example.com') {
        setErrors({ general: 'Invalid email or password. Please try again.' });
        setIsLoading(false);
      } else {
        login(email, 'Alex Rivera');
        setIsLoading(false);
        navigate('/dashboard');
      }
    }, 1200);
  };

  const handleSocial = (provider: 'Google' | 'Facebook') => {
    setIsLoading(true);
    setTimeout(() => {
      socialLogin(provider);
      setIsLoading(false);
      navigate('/dashboard');
    }, 1200);
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4 py-12">
      <div className="max-w-md w-full bg-white rounded-3xl p-8 border border-gray-100 shadow-xl shadow-blue-500/5 animate-fade-in">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-600/20">
            <span className="text-white font-bold text-3xl">N</span>
          </div>
          <h1 className="text-2xl font-bold text-slate-900">Welcome Back</h1>
          <p className="text-gray-500 text-sm mt-1">Sign in to your NovaCase account.</p>
        </div>

        {errors.general && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 text-red-600 text-sm animate-shake">
            <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
            {errors.general}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-1">
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">Email Address</label>
            <input 
              type="email" 
              className={`checkout-input ${errors.email ? 'border-red-500 focus:border-red-500' : ''}`}
              placeholder="name@example.com"
              value={email}
              onChange={e => {setEmail(e.target.value); if(errors.email) setErrors({...errors, email: undefined})}}
              disabled={isLoading}
            />
            {errors.email && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.email}</p>}
          </div>
          <div className="space-y-1">
            <div className="flex justify-between items-center ml-1">
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">Password</label>
              <Link to="/forgot-password" variant="ghost" className="text-blue-600 text-[10px] font-bold uppercase tracking-widest hover:underline">Forgot?</Link>
            </div>
            <input 
              type="password" 
              className={`checkout-input ${errors.password ? 'border-red-500 focus:border-red-500' : ''}`}
              placeholder="••••••••"
              value={password}
              onChange={e => {setPassword(e.target.value); if(errors.password) setErrors({...errors, password: undefined})}}
              disabled={isLoading}
            />
            {errors.password && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.password}</p>}
          </div>

          <div className="flex items-center justify-between py-2">
            <label className="flex items-center gap-2 cursor-pointer group">
              <input 
                type="checkbox" 
                checked={rememberMe} 
                onChange={(e) => setRememberMe(e.target.checked)}
                className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer" 
              />
              <span className="text-sm text-gray-500 group-hover:text-slate-900 transition-colors">Remember me</span>
            </label>
          </div>

          <button 
            type="submit" 
            disabled={isLoading}
            className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-blue-600 transition-all shadow-xl hover:shadow-blue-500/10 active:scale-[0.98] disabled:bg-gray-400 flex items-center justify-center gap-2"
          >
            {isLoading ? 'Processing...' : 'Sign In'}
          </button>
        </form>

        <div className="mt-8 pt-8 border-t text-center">
          <p className="text-sm text-gray-500">
            New to NovaCase? {' '}
