import React, { useState, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { products, CATEGORIES } from '../../data/products';
import ProductCard from '../components/ProductCard';

const ProductListingPage: React.FC = () => {
  const { categoryId } = useParams<{ categoryId: string }>();
  const [sortBy, setSortBy] = useState('popular');
  const [filterModel, setFilterModel] = useState('all');
  const [inStockOnly, setInStockOnly] = useState(false);

  const filteredProducts = useMemo(() => {
    let result = categoryId === 'all' 
      ? products 
      : products.filter(p => p.category.toLowerCase().replace(' ', '-') === categoryId);

    if (filterModel !== 'all') {
      result = result.filter(p => p.modelCompatibility.includes(filterModel));
    }

    if (inStockOnly) {
      result = result.filter(p => (p.stock === undefined || p.stock > 0));
    }

    if (sortBy === 'price-low') {
      result = [...result].sort((a, b) => a.price - b.price);
    } else if (sortBy === 'price-high') {
      result = [...result].sort((a, b) => b.price - a.price);
    }

    return result;
  }, [categoryId, sortBy, filterModel, inStockOnly]);

  const categoryName = categoryId === 'all' ? 'All Products' : CATEGORIES.find(c => c.toLowerCase().replace(' ', '-') === categoryId) || categoryId;

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Breadcrumbs */}
      <nav className="flex text-sm text-gray-400 mb-10" aria-label="Breadcrumb">
        <Link to="/" className="hover:text-indigo-600 transition-colors">Home</Link>
        <span className="mx-2">/</span>
        <span className="text-slate-900 font-semibold capitalize">{categoryName}</span>
      </nav>

      <div className="flex flex-col md:flex-row gap-12">
        {/* Sidebar Filters */}
        <aside className="w-full md:w-64 space-y-12 select-none">
          {/* Categories */}
          <div>
            <div className="space-y-4">
              {CATEGORIES.map(cat => {
                const isActive = cat.toLowerCase().replace(' ', '-') === categoryId || (cat === 'All' && categoryId === 'all');
                return (
                  <Link 
                    key={cat}
                    to={cat === 'All' ? '/category/all' : `/category/${cat.toLowerCase().replace(' ', '-')}`}
                    className={`block text-[15px] transition-all duration-200 ${isActive ? 'text-indigo-600 font-bold' : 'text-slate-500 hover:text-indigo-500'}`}
                  >
                    {cat}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Model Compatibility */}
          <div>
            <h4 className="font-black text-slate-900 mb-6 uppercase tracking-widest text-[11px]">Model Compatibility</h4>
            <div className="space-y-4">
              {['iPhone 15 Pro Max', 'iPhone 15 Pro', 'iPhone 15', 'Samsung S24 Ultra', 'All Models'].map(model => {
                const value = model === 'All Models' ? 'all' : model;
                const isChecked = filterModel === value;
                return (
                  <label key={model} className="flex items-center gap-4 cursor-pointer group">
                    <div className="relative flex items-center justify-center">
                      <input 
                        type="radio" 
                        name="model" 
                        checked={isChecked}
                        onChange={() => setFilterModel(value)}
                        className="sr-only" 
                      />
                      <div className={`w-[18px] h-[18px] rounded-full transition-all duration-200 border-2 ${
                        isChecked 
                          ? 'border-indigo-500 bg-white ring-[3px] ring-inset ring-indigo-500' 
                          : 'border-transparent bg-slate-700 group-hover:bg-slate-600'
                      }`} />
                    </div>
                    <span className={`text-[15px] transition-colors ${isChecked ? 'text-slate-900 font-semibold' : 'text-slate-500 group-hover:text-slate-700'}`}>
                      {model}
                    </span>
                  </label>
                );
              })}
            </div>
          </div>

          {/* Availability */}
          <div>
            <h4 className="font-black text-slate-900 mb-6 uppercase tracking-widest text-[11px]">Availability</h4>
            <label className="flex items-center gap-4 cursor-pointer group">
              <div className="relative flex items-center justify-center">
                <input 
                  type="checkbox" 
                  checked={inStockOnly}
                  onChange={(e) => setInStockOnly(e.target.checked)}
                  className="sr-only" 
                />
                <div className={`w-[18px] h-[18px] rounded transition-all duration-200 flex items-center justify-center ${
                  inStockOnly 
                    ? 'bg-indigo-600 shadow-lg shadow-indigo-500/20' 
                    : 'bg-slate-700 group-hover:bg-slate-600'
                }`}>
                  {inStockOnly && (
                    <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                    </svg>
                  )}
                </div>
              </div>
              <span className={`text-[15px] transition-colors ${inStockOnly ? 'text-slate-900 font-semibold' : 'text-slate-500 group-hover:text-slate-700'}`}>
                In Stock Only
              </span>
            </label>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-grow">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-10 gap-6">
            <h1 className="text-4xl font-black text-slate-900 tracking-tight capitalize">{categoryName}</h1>
            <div className="flex items-center gap-6">
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{filteredProducts.length} Results</span>
              <div className="relative">
                <select 
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                  className="appearance-none bg-white border-2 border-slate-100 rounded-2xl pl-6 pr-12 py-3 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all cursor-pointer"
                >
                  <option value="popular">Most Popular</option>
                  <option value="price-low">Price: Low to High</option>
                  <option value="price-high">Price: High to Low</option>
                </select>
                <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7"/></svg>
                </div>
              </div>
            </div>
          </div>

          {filteredProducts.length > 0 ? (
            <div className="grid grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} />
              ))}
            </div>
          ) : (
            <div className="bg-white rounded-[3rem] py-32 text-center border-2 border-slate-50 shadow-sm animate-fade-in">
              <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 text-slate-200">
                <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Zero matches found</h3>
              <p className="text-slate-400 mt-3 max-w-xs mx-auto">Try refining your filters or exploring a different collection.</p>
              <button 
                onClick={() => {setFilterModel('all'); setInStockOnly(false);}}
                className="mt-10 text-indigo-600 font-bold hover:underline underline-offset-8"
              >
                Reset All Filters
              </button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

