      if (email === 'error@example.com') {
        setErrors({ general: 'Invalid email or password. Please try again.' });
        setIsLoading(false);
      } else {
        login(email, 'Alex Rivera');
        setIsLoading(false);
        navigate('/dashboard');
      }
    }, 1200);
