import React, { useState, useMemo } from 'react';
import { useParams, Link, useSearchParams } from 'react-router-dom';
import { products, CATEGORIES } from '../../data/products';
import ProductCard from '../components/ProductCard';
import { useApp } from '../../context/AppContext';

const ProductListingPage: React.FC = () => {
  const { categoryId } = useParams<{ categoryId: string }>();
  const [searchParams] = useSearchParams();
  const searchQuery = searchParams.get('q');

  const { selectedDevice, setSelectedDevice } = useApp();
  const [sortBy, setSortBy] = useState('popular');
  const [inStockOnly, setInStockOnly] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Sync internal filter with global device context
  const filterModel = selectedDevice;

  const filteredProducts = useMemo(() => {
    let result = products;

    // 1. Primary Filter: Category OR Search
    if (categoryId) {
       // Category mode
       if (categoryId !== 'all') {
         result = result.filter(p => p.category.toLowerCase().replace(' ', '-') === categoryId);
       }
    } else if (searchQuery) {
       // Search mode
       const q = searchQuery.toLowerCase();
       result = result.filter(p => 
         p.name.toLowerCase().includes(q) || 
         p.description.toLowerCase().includes(q) ||
         p.category.toLowerCase().includes(q)
       );
    }

    // 2. Compatibility Filter
    if (filterModel !== 'all') {
      result = result.filter(p => p.modelCompatibility.includes(filterModel));
    }

    // 3. Stock Filter
    if (inStockOnly) {
      result = result.filter(p => (p.stock === undefined || p.stock > 0));
    }

    // 4. Sort
    if (sortBy === 'price-low') {
      result = [...result].sort((a, b) => a.price - b.price);
    } else if (sortBy === 'price-high') {
      result = [...result].sort((a, b) => b.price - a.price);
    }

    return result;
  }, [categoryId, searchQuery, sortBy, filterModel, inStockOnly]);

  const pageTitle = categoryId 
    ? (categoryId === 'all' ? 'All Products' : CATEGORIES.find(c => c.toLowerCase().replace(' ', '-') === categoryId) || categoryId)
    : `Results for "${searchQuery}"`;

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      {/* Breadcrumbs */}
      <nav className="flex text-[11px] font-black uppercase tracking-[0.2em] text-slate-300 mb-10" aria-label="Breadcrumb">
        <Link to="/" className="hover:text-indigo-600 transition-colors">Home</Link>
        <span className="mx-3 opacity-30">/</span>
        <span className="text-slate-900 truncate max-w-[200px]">{pageTitle}</span>
      </nav>

      <div className="flex flex-col md:flex-row gap-16">
        {/* Mobile Filter Toggle */}
        <button 
          className="md:hidden w-full bg-white border border-slate-200 p-4 rounded-2xl flex items-center justify-between shadow-sm hover:border-indigo-500 transition-all group"
          onClick={() => setShowFilters(!showFilters)}
        >
           <div className="flex items-center gap-3 font-bold text-slate-900 group-hover:text-indigo-600">
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4"/></svg>
             <span>Filters & Compatibility</span>
           </div>
           <svg className={`w-5 h-5 text-slate-400 transition-transform ${showFilters ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/></svg>
        </button>

        {/* Sidebar Filters */}
        <aside className={`w-full md:w-64 space-y-12 select-none ${showFilters ? 'block' : 'hidden md:block'}`}>
          {/* Categories */}
          <div>
            <h4 className="font-black text-slate-900 mb-8 uppercase tracking-widest text-[11px]">Collection</h4>
            <div className="space-y-5">
              {CATEGORIES.map(cat => {
                // Active state logic only applies when in category browsing mode
                const isActive = categoryId && (cat.toLowerCase().replace(' ', '-') === categoryId || (cat === 'All' && categoryId === 'all'));
                return (
                  <Link 
                    key={cat}
                    to={cat === 'All' ? '/category/all' : `/category/${cat.toLowerCase().replace(' ', '-')}`}
                    className={`block text-[15px] transition-all duration-300 flex items-center justify-between group ${isActive ? 'text-indigo-600 font-black translate-x-1' : 'text-slate-500 hover:text-indigo-500'}`}
                  >
                    {cat}
                    <div className={`w-1.5 h-1.5 rounded-full bg-indigo-600 transition-all ${isActive ? 'opacity-100' : 'opacity-0 group-hover:opacity-30'}`}></div>
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Model Compatibility */}
          <div>
            <h4 className="font-black text-slate-900 mb-8 uppercase tracking-widest text-[11px]">My Device</h4>
            <div className="space-y-5">
              {['iPhone 15 Pro Max', 'iPhone 15 Pro', 'iPhone 15', 'Samsung S24 Ultra', 'All Models'].map(model => {
                const value = model === 'All Models' ? 'all' : model;
                const isChecked = filterModel === value;
                return (
                  <label key={model} className="flex items-center gap-4 cursor-pointer group">
                    <div className="relative flex items-center justify-center">
                      <input 
                        type="radio" 
                        name="model" 
                        checked={isChecked}
                        onChange={() => setSelectedDevice(value)}
                        className="sr-only" 
                      />
                      <div className={`w-[18px] h-[18px] rounded-full transition-all duration-300 border-2 ${
                        isChecked 
                          ? 'border-indigo-600 bg-white ring-[4px] ring-inset ring-indigo-600' 
                          : 'border-transparent bg-slate-200 group-hover:bg-slate-300'
                      }`} />
                    </div>
                    <span className={`text-[15px] transition-colors ${isChecked ? 'text-slate-900 font-black' : 'text-slate-500 group-hover:text-slate-800'}`}>
                      {model}
                    </span>
                  </label>
                );
              })}
            </div>
          </div>

          {/* Availability */}
          <div className="pt-8 border-t border-slate-100">
            <h4 className="font-black text-slate-900 mb-8 uppercase tracking-widest text-[11px]">Availability</h4>
            <label className="flex items-center gap-4 cursor-pointer group">
              <div className="relative flex items-center justify-center">
                <input 
                  type="checkbox" 
                  checked={inStockOnly}
                  onChange={(e) => setInStockOnly(e.target.checked)}
                  className="sr-only" 
                />
                <div className={`w-[20px] h-[20px] rounded-lg transition-all duration-300 flex items-center justify-center ${
                  inStockOnly 
                    ? 'bg-indigo-600 shadow-xl shadow-indigo-500/20' 
                    : 'bg-slate-200 group-hover:bg-slate-300'
                }`}>
                  {inStockOnly && (
                    <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                    </svg>
                  )}
                </div>
              </div>
              <span className={`text-[15px] transition-colors ${inStockOnly ? 'text-slate-900 font-black' : 'text-slate-500 group-hover:text-slate-800'}`}>
                In Stock Only
              </span>
            </label>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-grow">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-16 gap-8">
            <div>
               <h1 className="text-4xl sm:text-5xl font-black text-slate-900 tracking-tighter capitalize mb-2">{pageTitle}</h1>
               <div className="flex items-center gap-2">
                 <div className="h-1 w-8 bg-indigo-600 rounded-full"></div>
                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">{filteredProducts.length} Premium Options</span>
               </div>
            </div>

            <div className="flex items-center gap-4 bg-slate-50 p-2 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4 hidden lg:block">Sort By:</span>
              <div className="relative">
                <select 
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                  className="appearance-none bg-white border border-slate-200 rounded-xl pl-6 pr-12 py-3 text-xs font-black text-slate-900 uppercase tracking-widest outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 transition-all cursor-pointer"
                >
                  <option value="popular">Popularity</option>
                  <option value="price-low">Price: Low-High</option>
                  <option value="price-high">Price: High-Low</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                </div>
              </div>
            </div>
          </div>

          {filteredProducts.length > 0 ? (
            <div className="grid grid-cols-2 lg:grid-cols-3 gap-8 sm:gap-12 animate-fade-in">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} />
              ))}
            </div>
          ) : (
            <div className="bg-white rounded-[4rem] py-40 text-center border border-slate-50 shadow-sm animate-fade-in">
              <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-10 text-slate-200">
                <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tight">No matches found.</h3>
              <p className="text-slate-400 mt-4 max-w-sm mx-auto font-medium">We couldn't find anything matching your criteria. Try different keywords or filters.</p>
              <button 
                onClick={() => {setSelectedDevice('all'); setInStockOnly(false);}}
                className="mt-12 bg-slate-900 text-white px-10 py-4 rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:bg-indigo-600 transition-all shadow-xl shadow-indigo-500/10 active:scale-95"
              >
                Clear Filters
              </button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

