    p.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setNewProduct({ ...newProduct, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const uploadToFirebase = async (file: File): Promise<string> => {
    // This is a placeholder for actual Firebase logic. 
    // To use real Firebase, you'd import { getStorage, ref, uploadBytesResumable, getDownloadURL } from "firebase/storage"
    return new Promise((resolve, reject) => {
      let progress = 0;
      const interval = setInterval(() => {
        progress += 20;
        setUploadProgress(progress);
        if (progress >= 100) {
          clearInterval(interval);
          // Simulated Firebase URL
          resolve(`https://firebasestorage.googleapis.com/v0/b/fauda-shop/o/products%2F${Date.now()}_${file.name}?alt=media`);
        }
      }, 200);
    });
  };

