    try {
      // 1. Upload to Firebase Storage
      const firebaseImageUrl = await uploadToFirebase(imageFile);

      // 2. Save Product Data and Firebase URL to MySQL via Backend
      const response = await fetch('http://localhost:5000/api/products', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
