const express = require('express');
const mysql = require('mysql2');
const cors = require('cors');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors());
app.use(express.json());

// Database Connection
const db = mysql.createConnection({
  host: process.env.DB_HOST || 'localhost',
  user: process.env.DB_USER || 'root',
  password: process.env.DB_PASSWORD || '',
  database: process.env.DB_NAME || 'fauda_shop'
});

db.connect(err => {
  if (err) {
    console.error('Error connecting to MySQL:', err);
    return;
  }
  console.log('Connected to MySQL Database');
});

// Routes

/**
 * 1. Add Product
 * Now accepts a standard JSON body.
 * Expects 'imageUrl' from Firebase Storage.
 */
app.post('/api/products', (req, res) => {
  const { name, category, price, stock, description, modelCompatibility, imageUrl } = req.body;

  if (!name || !price || !imageUrl) {
    return res.status(400).json({ error: 'Missing required fields (name, price, or image URL)' });
  }

  const sql = 'INSERT INTO products (name, category, price, stock, description, model_compatibility, image_url) VALUES (?, ?, ?, ?, ?, ?, ?)';

  db.query(sql, [name, category, price, stock, description, modelCompatibility, imageUrl], (err, result) => {
    if (err) {
      console.error('Database Error:', err);
      return res.status(500).json({ error: 'Database error occurred while saving product' });
    }
    res.status(201).json({ 
      message: 'Product added successfully', 
      id: result.insertId, 
      imageUrl 
    });
  });
});

/**
 * 2. Get All Products
 */
app.get('/api/products', (req, res) => {
  const sql = 'SELECT * FROM products ORDER BY id DESC';
  db.query(sql, (err, results) => {
    if (err) {
        console.error('Database Error:', err);
        return res.status(500).json({ error: 'Database error' });
    }
    res.json(results);
  });
});

app.listen(PORT, () => {
  console.log(`FAUDA Backend running on port ${PORT}`);
});

