import React, { useState, useEffect, useRef } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { AppProvider, useApp } from './context/AppContext';
import Navbar from './client/components/Navbar';
import CategoryBar from './client/components/CategoryBar';
import Hero from './client/components/Hero';
import ProductCard from './client/components/ProductCard';
import TrustSection from './client/components/TrustSection';
import Footer from './client/components/Footer';
import Toast from './client/components/Toast';
import AnnouncementBar from './client/components/AnnouncementBar';
import { CATEGORIES } from './data/products';

// Client Pages
import ProductListingPage from './client/pages/ProductListingPage';
import ProductDetailPage from './client/pages/ProductDetailPage';
import CartPage from './client/pages/CartPage';
import FavoritesPage from './client/pages/FavoritesPage';
import CheckoutPage from './client/pages/CheckoutPage';
import LoginPage from './client/pages/Auth/LoginPage';
import RegisterPage from './client/pages/Auth/RegisterPage';
import ForgotPasswordPage from './client/pages/Auth/ForgotPasswordPage';
import Dashboard from './client/pages/Dashboard/Dashboard';
import OrderDetailsPage from './client/pages/Dashboard/OrderDetailsPage';
import ContactPage from './client/pages/Info/ContactPage';
import FAQPage from './client/pages/Info/FAQPage';
import PolicyPage from './client/pages/Info/PolicyPage';

// Admin Pages
import AdminLogin from './admin/pages/AdminLogin';
import AdminLayout from './admin/pages/AdminLayout';
import AdminDashboard from './admin/pages/AdminDashboard';
import AdminOrders from './admin/pages/AdminOrders';
import AdminProducts from './admin/pages/AdminProducts';
import AdminInventory from './admin/pages/AdminInventory';
import AdminUsers from './admin/pages/AdminUsers';
import AdminAnalytics from './admin/pages/AdminAnalytics';

const HomePage: React.FC = () => {
  const [activeCategory, setActiveCategory] = useState('All');
  const sectionRefs = useRef<{ [key: string]: HTMLElement | null }>({});
  const { products } = useApp(); // Use dynamic products

  const handleCategoryClick = (category: string) => {
    setActiveCategory(category);
    if (category === 'All') {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      const element = sectionRefs.current[category];
      if (element) {
        const offset = 140; 
        const elementPosition = element.getBoundingClientRect().top + window.scrollY;
        window.scrollTo({
          top: elementPosition - offset,
          behavior: 'smooth'
        });
      }
    }
  };

  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '-20% 0px -70% 0px',
      threshold: 0
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveCategory(entry.target.id);
        }
      });
    }, observerOptions);

    Object.values(sectionRefs.current).forEach((ref) => {
      if (ref instanceof Element) {
        observer.observe(ref);
      }
    });

    return () => observer.disconnect();
  }, []);

  return (
    <div className="min-h-screen">
      <Hero />
      <CategoryBar activeCategory={activeCategory} onCategoryClick={handleCategoryClick} />

      <main className="max-w-7xl mx-auto px-4 py-12 space-y-20">
        {CATEGORIES.filter(cat => cat !== 'All').map(category => (
          <section 
            key={category} 
            id={category}
            ref={el => { sectionRefs.current[category] = el; }}
            className="scroll-mt-32"
          >
            <div className="flex items-end justify-between mb-8">
              <div>
                <h2 className="text-3xl font-extrabold text-slate-900 mb-2">{category}</h2>
                <p className="text-gray-500">Premium quality and precision engineered.</p>
              </div>
              <Link 
                to={`/category/${category.toLowerCase().replace(' ', '-')}`} 
                className="text-blue-600 font-bold text-sm hover:underline flex items-center gap-1 group"
              >
                View All 
                <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
              </Link>
            </div>

            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
              {products
                .filter(p => p.category === category)
                .slice(0, 10)
                .map(product => (
                  <ProductCard key={product.id} product={product} />
                ))
              }
            </div>
          </section>
        ))}
      </main>

      <TrustSection />
    </div>
  );
};

const AppRoutes: React.FC = () => {
  const location = useLocation();
  const isAdminPath = location.pathname.startsWith('/admin');

  return (
    <div className="flex flex-col min-h-screen">
      {!isAdminPath && <AnnouncementBar />}
      {!isAdminPath && <Navbar />}
      <div className="flex-grow">
        <Routes>
          {/* User Routes */}
          <Route path="/" element={<HomePage />} />
          <Route path="/category/:categoryId" element={<ProductListingPage />} />
          <Route path="/search" element={<ProductListingPage />} />
          <Route path="/product/:productId" element={<ProductDetailPage />} />
          <Route path="/cart" element={<CartPage />} />
          <Route path="/favorites" element={<FavoritesPage />} />
          <Route path="/checkout" element={<CheckoutPage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/order/:orderId" element={<OrderDetailsPage />} />
          <Route path="/contact" element={<ContactPage />} />
          <Route path="/faq" element={<FAQPage />} />
          <Route path="/policy/:type" element={<PolicyPage />} />

          {/* Admin Routes */}
          <Route path="/admin/login" element={<AdminLogin />} />
          <Route path="/admin" element={<AdminLayout />}>
            <Route path="dashboard" element={<AdminDashboard />} />
            <Route path="analytics" element={<AdminAnalytics />} />
            <Route path="orders" element={<AdminOrders />} />
            <Route path="products" element={<AdminProducts />} />
            <Route path="inventory" element={<AdminInventory />} />
            <Route path="users" element={<AdminUsers />} />
          </Route>
        </Routes>
      </div>
      {!isAdminPath && <Footer />}
      <Toast />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <Router>
        <AppRoutes />
      </Router>
    </AppProvider>
  );
};

export default App;

