      className={`group relative bg-white rounded-3xl overflow-hidden border border-slate-100 transition-all duration-500 flex flex-col h-full hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-1 ${!isDirectlyCompatible ? 'opacity-40 grayscale-[0.5] hover:opacity-100 hover:grayscale-0' : ''}`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
