              </div>
            ))}
            {(!product.reviews || product.reviews.length === 0) && (
              <p className="text-gray-500">No reviews yet.</p>
            )}
          </div>
        )}
      </div>

      {/* Recommended */}
      <section>
        <h2 className="text-2xl font-bold text-slate-900 mb-8">You May Also Like</h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
          {products.filter(p => p.category === product.category && p.id !== product.id).slice(0, 4).map(p => (
            <ProductCard key={p.id} product={p} />
          ))}
        </div>
      </section>
    </div>
  );
};

export default ProductDetailPage;

export interface Review {
  id: string;
  user: string;
  rating: number;
  comment: string;
  date: string;
}

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  image: string;
  images: string[];
  modelCompatibility: string;
  description: string;
  specifications: string[];
  isBestSeller?: boolean;
  reviews?: Review[];
  stock?: number;
  colors?: string[]; // Array of hex codes
}

export interface CartItem extends Product {
  quantity: number;
  selectedColor?: string;
}

export type Category = 'All' | 'Clear Cases' | 'MagSafe' | 'Screen Protectors' | 'Chargers' | 'Lens Guards';

export type PaymentMethodType = 'COD' | 'bKash' | 'Nagad' | 'SSLCommerz' | 'Bank' | 'Card';

export interface ShippingInfo {
  fullName: string;
  phone: string;
  email: string;
  address: string;
  city: string;
  area: string;
  postalCode: string;
  note?: string;
}

export interface Order {
  id: string;
  items: CartItem[];
  shipping: ShippingInfo;
  payment: {
    method: PaymentMethodType;
    details?: any;
  };
  subtotal: number;
  tax: number;
  shippingFee: number;
  total: number;
  status: 'Processing' | 'Shipped' | 'Delivered' | 'Cancelled';
  date: string;
}

export interface Address extends ShippingInfo {
  id: string;
  isDefault: boolean;
}

export interface User {
  id: string;
  email: string;
  fullName: string;
  phone?: string;
  addresses: Address[];
  role: 'admin' | 'user';
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Product, CartItem, Order, ShippingInfo, PaymentMethodType, User, Address } from '../types';
import { products as mockProducts } from '../data/products'; // Keep as fallback

interface AppContextType {
  products: Product[];
  cart: CartItem[];
  wishlist: string[];
  orders: Order[];
  user: User | null;
  selectedDevice: string;
  setSelectedDevice: (device: string) => void;
  rememberMe: boolean;
  setRememberMe: (val: boolean) => void;
  addToCart: (product: Product, quantity?: number, color?: string) => void;
  buyNow: (product: Product, quantity?: number, color?: string) => void;
  updateCartQuantity: (productId: string, delta: number, color?: string) => void;
  removeFromCart: (productId: string, color?: string) => void;
  toggleWishlist: (productId: string) => void;
  clearCart: () => void;
  placeOrder: (shipping: ShippingInfo, paymentMethod: PaymentMethodType, paymentDetails: any) => Order;
  login: (email: string, fullName: string) => void;
  adminLogin: (email: string) => void;
  socialLogin: (provider: 'Google' | 'Facebook') => void;
  logout: () => void;
  updateProfile: (data: Partial<User>) => void;
  addAddress: (address: Omit<Address, 'id' | 'isDefault'>) => void;
  removeAddress: (id: string) => void;
  updateOrderStatus: (orderId: string, status: Order['status']) => void;
  cartCount: number;
  wishlistCount: number;
  cartTotal: number;
  toast: { message: string; visible: boolean } | null;
  showToast: (message: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(mockProducts);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [selectedDevice, setSelectedDevice] = useState<string>(() => {
    return localStorage.getItem('fauda_device') || 'all';
  });
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('fauda_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [rememberMe, setRememberMe] = useState(() => {
    return localStorage.getItem('fauda_remember') === 'true';
  });
  const [toast, setToast] = useState<{ message: string; visible: boolean } | null>(null);

  // Fetch Products from Backend to get Admin updates
  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/products');
        if (response.ok) {
          const dbProducts = await response.json();
          // Map DB structure to Frontend Product structure
          const formattedProducts: Product[] = dbProducts.map((p: any) => ({
            id: p.id.toString(),
            name: p.name,
            category: p.category,
            price: parseFloat(p.price),
            image: p.image_url, // Use the URL from Firebase/DB
            images: [p.image_url], // Fallback for gallery
            modelCompatibility: p.model_compatibility || 'All Models',
            description: p.description,
            specifications: ['Premium Quality'],
            stock: p.stock,
            isBestSeller: false,
            colors: []
          }));

          // Merge with mock products (placing DB products first)
          setProducts([...formattedProducts, ...mockProducts]);
        }
      } catch (error) {
        console.log("Using offline data");
      }
    };
    fetchProducts();
  }, []);

  useEffect(() => {
    localStorage.setItem('fauda_device', selectedDevice);
  }, [selectedDevice]);

  useEffect(() => {
    if (rememberMe && user) {
      localStorage.setItem('fauda_user', JSON.stringify(user));
    } else {
      localStorage.removeItem('fauda_user');
    }
    localStorage.setItem('fauda_remember', rememberMe.toString());
  }, [user, rememberMe]);

  const showToast = (message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => setToast(null), 3000);
  };

  const addToCart = (product: Product, quantity: number = 1, color?: string) => {
    setCart(prev => {
      // Find item with same ID AND same color (if color is specified)
      const existing = prev.find(item => item.id === product.id && item.selectedColor === color);

      if (existing) {
        return prev.map(item =>
          (item.id === product.id && item.selectedColor === color) 
            ? { ...item, quantity: item.quantity + quantity } 
            : item
        );
      }
      return [...prev, { ...product, quantity, selectedColor: color }];
    });

    const colorText = color ? ` (${color})` : '';
    showToast(`${product.name}${colorText} added to cart!`);
  };

  const buyNow = (product: Product, quantity: number = 1, color?: string) => {
    addToCart(product, quantity, color);
  };

  const updateCartQuantity = (productId: string, delta: number, color?: string) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId && item.selectedColor === color) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (productId: string, color?: string) => {
    setCart(prev => prev.filter(item => !(item.id === productId && item.selectedColor === color)));
    showToast('Removed from cart');
  };

  const clearCart = () => setCart([]);

  const placeOrder = (shipping: ShippingInfo, method: PaymentMethodType, details: any): Order => {
    const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const shippingFee = subtotal > 50 ? 0 : 9.99;
    const tax = subtotal * 0.08;
    const total = subtotal + shippingFee + tax;

    const newOrder: Order = {
      id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      items: [...cart],
      shipping,
      payment: { method, details },
      subtotal,
      tax,
      shippingFee,
      total,
      status: 'Processing',
      date: new Date().toISOString()
    };

    setOrders(prev => [newOrder, ...prev]);
    clearCart();
    return newOrder;
  };

  const login = (email: string, fullName: string) => {
    setUser({ id: 'USR-1', email, fullName, addresses: [], role: 'user' });
    showToast(`Welcome back, ${fullName}!`);
  };

  const adminLogin = (email: string) => {
    setUser({ id: 'ADM-1', email, fullName: 'System Administrator', addresses: [], role: 'admin' });
    showToast(`Admin session started.`);
  };

  const socialLogin = (provider: 'Google' | 'Facebook') => {
    setUser({ id: `USR-${provider.toUpperCase()}`, email: `social.${provider.toLowerCase()}@example.com`, fullName: `${provider} User`, addresses: [], role: 'user' });
    showToast(`Signed in with ${provider} successfully!`);
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('fauda_user');
    showToast('Logged out successfully');
  };

  const updateProfile = (data: Partial<User>) => {
    if (user) {
      setUser({ ...user, ...data });
      showToast('Profile updated');
    }
  };

  const addAddress = (addr: Omit<Address, 'id' | 'isDefault'>) => {
    if (user) {
      const newAddress: Address = { ...addr, id: Math.random().toString(36).substr(2, 9), isDefault: user.addresses.length === 0 };
      setUser({ ...user, addresses: [...user.addresses, newAddress] });
      showToast('Address added');
    }
  };

  const removeAddress = (id: string) => {
    if (user) {
      setUser({ ...user, addresses: user.addresses.filter(a => a.id !== id) });
      showToast('Address removed');
    }
  };

  const updateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
    showToast(`Order ${orderId} status updated to ${status}`);
  };

  const toggleWishlist = (productId: string) => {
    setWishlist(prev => {
      const isFav = prev.includes(productId);
      if (isFav) {
        showToast('Removed from favorites');
        return prev.filter(id => id !== productId);
      }
      showToast('Added to favorites');
      return [...prev, productId];
    });
  };

  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);
  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const wishlistCount = wishlist.length;

  return (
    <AppContext.Provider value={{ 
      products, 
      cart, wishlist, orders, user, selectedDevice, setSelectedDevice, rememberMe, setRememberMe,
      addToCart, buyNow, updateCartQuantity, removeFromCart, clearCart, placeOrder,
      login, adminLogin, socialLogin, logout, updateProfile, addAddress, removeAddress, updateOrderStatus,
      toggleWishlist, cartCount, wishlistCount, cartTotal, toast, showToast
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import { Product, Review } from '../types';

const generateReviews = (count: number): Review[] => {
  const users = ['Alex R.', 'Sarah M.', 'Jordan K.', 'Taylor B.', 'Casey W.'];
  const comments = [
    'Amazing quality! Fits perfectly.',
    'Fast shipping and great packaging.',
    'Highly recommended, looks very premium.',
    'The best case I have ever owned.',
    'Excellent value for the price.'
  ];
  return Array.from({ length: count }, (_, i) => ({
    id: `rev-${i}`,
    user: users[i % users.length],
    rating: 4 + Math.random(),
    comment: comments[i % comments.length],
    date: '2 days ago'
  }));
};

