          {['iPhone Case', 'Samsung Case', 'Accessories'].map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab as Tab)}
              className={`pb-4 text-xl font-medium whitespace-nowrap transition-all relative ${
                activeTab === tab 
                  ? 'text-slate-900' 
                  : 'text-gray-400 hover:text-slate-600'
              }`}
            >
              {tab}
              {activeTab === tab && (
                <span className="absolute bottom-0 left-0 w-full h-1 bg-orange-500 rounded-full"></span>
