import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { useApp } from '../../context/AppContext';
import ProductCard from '../components/ProductCard';
import LazyImage from '../components/LazyImage';

const ProductDetailPage: React.FC = () => {
  const { productId } = useParams<{ productId: string }>();
  const { addToCart, toggleWishlist, wishlist, products } = useApp();
  const navigate = useNavigate();

  // Find product in the context list (which includes API products)
  const product = products.find(p => p.id === productId);

  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Swipe State
  const [touchStart, setTouchStart] = useState(0);
  const [touchEnd, setTouchEnd] = useState(0);

  if (!product) return <div className="p-20 text-center">Product not found.</div>;

  const allImages = [product.image, ...(product.images || [])];
  const isFavorite = wishlist.includes(product.id);

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % allImages.length);
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + allImages.length) % allImages.length);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart(e.targetTouches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    setTouchEnd(e.targetTouches[0].clientX);
  };

  const handleTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distance = touchStart - touchEnd;
    const isLeftSwipe = distance > 50;
    const isRightSwipe = distance < -50;

    if (isLeftSwipe) {
      nextImage();
    }
    if (isRightSwipe) {
      prevImage();
    }
    setTouchStart(0);
    setTouchEnd(0);
  };

  const handleBuyNow = () => {
    addToCart(product, quantity);
    navigate('/checkout');
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <nav className="flex text-sm text-gray-500 mb-12" aria-label="Breadcrumb">
        <Link to="/" className="hover:text-blue-900">Home</Link>
        <span className="mx-2">/</span>
        <Link to="/category/all" className="hover:text-blue-900">Products</Link>
        <span className="mx-2">/</span>
        <span className="text-gray-900 font-medium">{product.name}</span>
      </nav>

      <div className="grid md:grid-cols-2 gap-12 mb-20">
        {/* Left: Gallery Carousel */}
        <div className="space-y-4 select-none">
          <div 
            className="relative aspect-square bg-gray-50 rounded-3xl overflow-hidden border border-gray-100 group"
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
          >
            {/* Carousel Track */}
            <div 
              className="flex h-full transition-transform duration-500 ease-out"
              style={{ transform: `translateX(-${currentImageIndex * 100}%)` }}
            >
              {allImages.map((img, idx) => (
                <div key={idx} className="min-w-full h-full">
                  <LazyImage src={img} alt={`${product.name} ${idx}`} className="w-full h-full object-cover" />
                </div>
              ))}
            </div>

            {/* Navigation Arrows (Desktop) */}
            <button 
              onClick={(e) => { e.preventDefault(); prevImage(); }}
              className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 backdrop-blur-md p-3 rounded-full shadow-lg text-slate-800 opacity-0 group-hover:opacity-100 transition-all hover:scale-110 hover:bg-white z-10"
              aria-label="Previous Image"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
            </button>
            <button 
              onClick={(e) => { e.preventDefault(); nextImage(); }}
              className="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 backdrop-blur-md p-3 rounded-full shadow-lg text-slate-800 opacity-0 group-hover:opacity-100 transition-all hover:scale-110 hover:bg-white z-10"
              aria-label="Next Image"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" /></svg>
            </button>

            {/* Pagination Dots */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2 z-10">
              {allImages.map((_, idx) => (
                <button 
                  key={idx}
                  onClick={() => setCurrentImageIndex(idx)}
                  className={`h-2 rounded-full transition-all duration-300 shadow-sm ${currentImageIndex === idx ? 'bg-white w-6 opacity-100' : 'bg-white/60 w-2 hover:bg-white/80'}`}
                  aria-label={`Go to slide ${idx + 1}`}
                />
              ))}
            </div>
          </div>

          {/* Thumbnails */}
          <div className="grid grid-cols-4 gap-4">
            {allImages.map((img, i) => (
              <button 
                key={i}
                onClick={() => setCurrentImageIndex(i)}
                className={`aspect-square rounded-xl overflow-hidden border-2 transition-all relative ${currentImageIndex === i ? 'border-blue-600 shadow-lg ring-2 ring-blue-100' : 'border-transparent opacity-70 hover:opacity-100'}`}
              >
                <LazyImage src={img} alt={`Thumbnail ${i}`} className="w-full h-full object-cover" />
                {currentImageIndex === i && <div className="absolute inset-0 bg-blue-600/10"></div>}
              </button>
            ))}
          </div>
        </div>

        {/* Right: Info */}
        <div className="flex flex-col">
          <div className="flex items-center gap-2 mb-4">
            <span className="bg-blue-900 text-white text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-widest">
              {product.category}
            </span>
            {product.isBestSeller && (
              <span className="bg-gradient-to-r from-purple-600 to-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-widest">
                Best Seller
              </span>
            )}
          </div>
          <h1 className="text-4xl font-extrabold text-slate-900 mb-2">{product.name}</h1>
          <p className="text-blue-700 font-medium text-lg mb-6">{product.modelCompatibility}</p>

          <div className="flex items-center gap-4 mb-8">
            <span className="text-4xl font-black text-slate-900">${product.price.toFixed(2)}</span>
            <div className="h-6 w-px bg-gray-200"></div>
            <div className="flex items-center text-amber-500 gap-1">
              <svg className="w-5 h-5 fill-current" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
              <span className="text-slate-800 font-bold">4.8</span>
              <span className="text-gray-400 text-sm font-medium">({product.reviews?.length || 0} Reviews)</span>
            </div>
          </div>

          <p className="text-gray-600 leading-relaxed mb-10 text-lg">
            {product.description}
          </p>

          <div className="space-y-6 mt-auto">
            <div className="flex items-center gap-6">
              <div className="flex items-center bg-gray-100 rounded-2xl p-1">
                <button 
                  onClick={() => setQuantity(Math.max(1, quantity - 1))}
                  className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-xl transition-all font-bold"
                >-</button>
                <span className="w-12 text-center font-bold text-slate-900">{quantity}</span>
                <button 
                  onClick={() => setQuantity(quantity + 1)}
                  className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-xl transition-all font-bold"
                >+</button>
              </div>
              <button 
                onClick={() => toggleWishlist(product.id)}
                className={`p-4 rounded-2xl border-2 transition-all ${isFavorite ? 'bg-red-50 border-red-100 text-red-500' : 'border-gray-100 text-gray-400 hover:text-red-500 hover:border-red-100'}`}
              >
                <svg className={`w-6 h-6 ${isFavorite ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={() => addToCart(product, quantity)}
                className="bg-slate-100 text-slate-900 py-5 rounded-2xl font-bold text-lg hover:bg-slate-200 transition-all active:scale-[0.98]"
              >
                Add to Cart
              </button>
              <button 
                onClick={handleBuyNow}
                className="bg-gradient-to-r from-blue-700 via-purple-600 to-red-500 text-white py-5 rounded-2xl font-bold text-lg hover:shadow-xl hover:shadow-purple-500/20 transition-all active:scale-[0.98]"
              >
                Buy Now
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b mb-12">
        <div className="flex gap-12 overflow-x-auto hide-scrollbar">
          {['description', 'specifications', 'reviews'].map(tab => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`pb-4 text-sm font-bold uppercase tracking-widest transition-all relative whitespace-nowrap ${activeTab === tab ? 'text-blue-900' : 'text-gray-400 hover:text-slate-900'}`}
            >
              {tab}
              {activeTab === tab && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-900 rounded-full" />}
            </button>
          ))}
        </div>
      </div>

      <div className="min-h-[200px] mb-20">
        {activeTab === 'description' && (
          <div className="prose prose-blue max-w-none text-gray-600 animate-fade-in">
            <p className="text-xl leading-relaxed">{product.description}</p>
          </div>
        )}
        {activeTab === 'specifications' && (
          <ul className="grid sm:grid-cols-2 gap-4 animate-fade-in">
            {(product.specifications || []).map((spec, i) => (
              <li key={i} className="flex items-center gap-3 p-4 bg-white rounded-2xl border border-gray-100">
                <div className="w-2 h-2 bg-blue-900 rounded-full" />
                <span className="text-slate-800 font-medium">{spec}</span>
              </li>
            ))}
          </ul>
        )}
        {activeTab === 'reviews' && (
          <div className="space-y-6 animate-fade-in">
            {product.reviews?.map(review => (
              <div key={review.id} className="p-6 bg-white rounded-3xl border border-gray-100">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-blue-50 rounded-full flex items-center justify-center text-blue-900 font-bold">
                      {review.user[0]}
                    </div>
                    <div>
                      <p className="font-bold text-slate-900">{review.user}</p>
                      <p className="text-xs text-gray-400">{review.date}</p>
                    </div>
                  </div>
                  <div className="flex text-amber-500">
                    {[...Array(5)].map((_, i) => (
                      <svg key={i} className={`w-4 h-4 ${i < Math.floor(review.rating) ? 'fill-current' : 'text-gray-200'}`} viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                    ))}
                  </div>
                </div>
                <p className="text-gray-600">{review.comment}</p>
              </div>
            ))}
            {(!product.reviews || product.reviews.length === 0) && (
              <p className="text-gray-500">No reviews yet.</p>
            )}
          </div>
        )}
      </div>

      {/* Recommended */}
      <section>
        <h2 className="text-2xl font-bold text-slate-900 mb-8">You May Also Like</h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
          {products.filter(p => p.category === product.category && p.id !== product.id).slice(0, 4).map(p => (
            <ProductCard key={p.id} product={p} />
          ))}
        </div>
      </section>
    </div>
  );
};

export default ProductDetailPage;

